+func getPrefixList(prefixes map[string]int) []string {
+	var result []string
+	keys := make([]string, 0, len(prefixes))
+	for k := range prefixes {
+		keys = append(keys, k)
+	}
+	sort.Strings(keys)
+	for _, prefix := range keys {
+		result = append(result, fmt.Sprintf("%s- (%d issues)", prefix, prefixes[prefix]))
+	}
+	return result
+}
