-	fc.strFrom = func(v interface{}) (string, bool) {
-		switch t := v.(type) {
-		case string:
-			return t, true
-		case *string:
-			if t == nil {
-				return "", true
-			}
-			return *t, true
-		case nil:
-			return "", true
-		default:
-			return "", false
-		}
-	}
-
-	fc.intFrom = func(v interface{}) (int64, bool) {
